// Filtrer et catégoriser les devis selon leur ancienneté
const devis = $input.all().map(item => item.json);
const maintenant = new Date();

const devisCategories = {
  urgents: [],   // +10 jours : relance finale + alerte interne
  relance: [],   // +5 jours : email de relance
  ok: []         // < 5 jours : rien à faire
};

devis.forEach(d => {
  const dateCreation = new Date(d.created_at || d.date);
  const joursEcoules = Math.floor((maintenant - dateCreation) / (1000 * 60 * 60 * 24));

  const devisEnrichi = {
    ...d,
    joursEcoules,
    dateCreationFr: dateCreation.toLocaleDateString('fr-FR'),
    montantFormate: new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR' }).format(d.amount || 0)
  };

  if (joursEcoules >= 10) devisCategories.urgents.push(devisEnrichi);
  else if (joursEcoules >= 5) devisCategories.relance.push(devisEnrichi);
  else devisCategories.ok.push(devisEnrichi);
});

console.log(`Devis analysés : ${devis.length} total | ${devisCategories.urgents.length} urgents | ${devisCategories.relance.length} à relancer | ${devisCategories.ok.length} OK`);

// Retourner tous les devis à traiter avec leur catégorie
const aTraiter = [
  ...devisCategories.urgents.map(d => ({ ...d, categorie: 'urgent' })),
  ...devisCategories.relance.map(d => ({ ...d, categorie: 'relance' }))
];

if (aTraiter.length === 0) {
  return [{ json: { aucunDevis: true, message: 'Aucun devis à relancer ce matin.' } }];
}

return aTraiter.map(d => ({ json: d }));

